#include <bits/stdc++.h>
using namespace std;

const int N=2e7+10;

struct Node{
    int son[4],len,fa;
}st[N];

int n,m,last=1,tot=1;
char s[N];

void extend(int c){
    int p=last,np=++tot;
    last=tot;
    st[np].len=st[p].len+1;
    for(;p && !st[p].son[c];p=st[p].fa) st[p].son[c]=np;
    if(!p){
        st[np].fa=1;
        return;
    }
    int q=st[p].son[c];
    if(st[q].len==st[p].len+1)
        st[np].fa=q;
    else{
        int nq=++tot;
        st[nq]=st[q],st[nq].len=st[p].len+1;
        st[q].fa=st[np].fa=nq;
        for(;p && st[p].son[c]==q;p=st[p].fa) st[p].son[c]=nq;
    }
}

int main(){
    scanf("%d%d",&n,&m);
    scanf("%s",s);
    for(int i=0;s[i];i++){
        if(s[i]=='E') extend(0);
        if(s[i]=='S') extend(1);
        if(s[i]=='W') extend(2);
        if(s[i]=='N') extend(3);
    }
    while(m--){
        scanf("%s",s);
        int cnt=0;
        for(int i=0,p=1;s[i] && p;i++){
            if(s[i]=='E') p=st[p].son[0];
            if(s[i]=='S') p=st[p].son[1];
            if(s[i]=='W') p=st[p].son[2];
            if(s[i]=='N') p=st[p].son[3];
            if(p) cnt++;
        }
        printf("%d\n",cnt);
    }
    return 0;
}
